mapper.select:
/* SQL ID : AsmntDAO.selectCrsCreList 설 명 : 과목 조회 */ SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO FROM TB_LMS_SBJCT A JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID JOIN CRS_SMSTR C ON B.CRS_SMSTR_ID = C.CRS_SMSTR_ID AND C.ORG_ID = #{orgId}
AND C.DGRS_YR = #{creYear}
AND C.DGRS_SMSTR = #{creTerm}
WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SBJCT_TYCD = 'UNI' AND EXISTS ( SELECT 1 FROM SBJCT_PROF WHERE SBJCT_ID = A.SBJCT_ID AND USER_ID = #{userId} AND PROF_TYCD != 'MONITORING' ) ORDER BY A.SBJCTNM, A.DVCLAS_NO

mapper.update:
		/*
             SQL ID : AsmntDAO.deleteStd
             	설  명 : 과제제출 삭제
         */	
		UPDATE TB_LMS_ASMT_SBMSN
		   SET DELYN = 'Y'
		 WHERE ASMT_ID = #{asmtId}
	       AND STD_ID = #{stdNo}

		/*
             SQL ID : AsmntDAO.deleteStdList
             	설  명 : 수강생 목록 삭제
         */

		UPDATE TB_LMS_ASMT_SBMSN
		SET DELYN = 'Y'
		WHERE ASMT_ID = #{item.asmtId}
			AND USER_ID = #{item.userId}

/*
  SQL ID : AsmntDAO.updateAsmntForTrans
  설  명 : 과제 수정(선수강과목 이관용)
*/

/* 과제 참여자 */
UPDATE TB_LMS_ASMT_SBMSN A
INNER JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B
	ON A.ASMT_ID = B.ASMT_ID 
SET 
	  A.STD_ID = REPLACE(A.STD_ID, #{crsCreCd}, #{newSbjctId})
	, A.DELYN = 'N'
WHERE B.SBJCT_ID = #{crsCreCd};

/* 과제 참여자 히스토리 */
UPDATE TB_LMS_ASMNT_JOIN_HSTY A
INNER JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B
	ON A.ASMT_ID = B.ASMT_ID 
SET 
	A.STD_ID = REPLACE(A.STD_ID, #{crsCreCd}, #{newSbjctId})
WHERE B.SBJCT_ID = #{crsCreCd};

/* 과제 댓글 */
UPDATE TB_LMS_ASMT_CMNT A
INNER JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B
	ON A.ASMT_ID = B.ASMT_ID 
SET 
	  A.STD_ID = REPLACE(A.STD_ID, #{crsCreCd}, #{newSbjctId})
	, A.SBJCT_ID = #{newSbjctId}
WHERE B.SBJCT_ID = #{crsCreCd};

/* 과제 피드백 */
UPDATE TB_LMS_ASMNT_FDBK A
INNER JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B
	ON A.ASMT_ID = B.ASMT_ID 
SET 
	  A.STD_ID = REPLACE(A.STD_ID, #{crsCreCd}, #{newSbjctId})
WHERE B.SBJCT_ID = #{crsCreCd};

/* 과제정보 */
UPDATE TB_LMS_ASMT A
INNER JOIN TB_LMS_ASMNT_CRE_CRS_RLTN B
	ON A.ASMT_ID = B.ASMT_ID 
SET 
	A.SBJCT_ID = #{newSbjctId}
WHERE B.SBJCT_ID = #{crsCreCd};

/* 과제 연결 */
UPDATE TB_LMS_ASMNT_CRE_CRS_RLTN A
INNER JOIN TB_LMS_ASMT B
	ON A.ASMT_ID = B.ASMT_ID 
SET 
	A.SBJCT_ID = #{newSbjctId}
WHERE A.SBJCT_ID = #{crsCreCd};
